from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""
    from collections import defaultdict
    subject_map = defaultdict(list)
    for t in triples:
        subject_map[t.subject].append(t)

    # Mapping from predicate to a concise phrase (object placeholder {obj})
    templates = {
        "cityServed": "serves the city of {obj}",
        "elevationAboveTheSeaLevel": "is {obj} metres above sea level",
        "runwayLength": "has a runway length of {obj}",
        "runwayName": "has a runway named {obj}",
        "location": "is located in {obj}",
        "country": "is in {obj}",
        "leader": "leader is {obj}",
        "capital": "capital is {obj}",
        # add more mappings as needed …
    }

    sentences = []
    for subject, tlist in subject_map.items():
        parts = []
        for t in tlist:
            tmpl = templates.get(t.predicate, f"{t.predicate.replace('_', ' ')} {{obj}}")
            obj = t.object.strip('"')
            parts.append(tmpl.format(obj=obj))

        if len(parts) == 1:
            sentence = f"{subject} {parts[0]}."
        else:
            sentence = f"{subject} " + ", ".join(parts[:-1]) + ", and " + parts[-1] + "."
        sentences.append(sentence)

    return " ".join(sentences)

# EVOLVE-BLOCK-END
